INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895ed","title":"Доктор Стар и королевство Несбывшегося","author":"Дэйв Стюарт,Джефф Лемир,Макс Фиумара,Нэйт Пикос","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002896663/140/748b/__Doktor_Star_i_korolevstvo_Nesbyvshegosya.jpg","isbn":"978-5-91339-711-9","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"Мир «Чёрного молота»","genres":["Комиксы","манга","графические романы"],"annotation":"МНОГОПЛАНОВАЯ ИСТОРИЯ, СОБЫТИЯ КОТОРОЙ ПРОИСХОДЯТ В МИРЕ КОМИКСА «ЧЁРНЫЙ МОЛОТ» (ЛАУРЕАТА ПРЕМИИ АЙСНЕРА), РАССКАЗЫВАЕТ О НАСЛЕДИИ СУПЕРГЕРОЯ ЗОЛОТОГО ВЕКА.  Пожилой супергерой отчаянно стремится наладить испортившиеся отношения с сыном, который, как он надеется, в будущем станет новым Доктором Старом. Из комикса мы узнаем историю времён Второй мировой о происхождении Доктора Стара, станем свидетелями того, как он заполучил свои силы, отправимся в иные миры, увидим величайших героев мира «Чёрного Молота» и пронаблюдаем, как геройская сага превращается в щемящую историю об отцах и детях.  В книге собраны все четыре номера «Доктора Стара» от автора бестселлеров по версии New York Times и обладателя премии Айснера Джеффа Лемира!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":4,"review":"","added":9999853,"hdCover":""},{"id":"09895ec","title":"Кафка-Кодекс","author":"Вера Челищева,Леонид Никитский,Дарья Петушок,Юлия Счастливцева,Алексей Иорш,Георгий Елаев,Сергей Лебеденко,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003287004/140/e0c5/__KafkaKodeks.jpg","isbn":"978-5-91339-862-8","publisher":"КомФедерация","pubDate":"2019","language":"Русский","series":"Комильфо. КомФедерация. Отечественные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Российская судебная система несовершенна. Её слуги всё чаще напоминают безликих фигур из рассказа Франца Кафки \"Приговор\". В новостях мы всё чаще видим абсурдные приговоры в отношении ни в чём не повинных людей, вновь и вновь заставляя нас задумываться не только о конституционности данных решений, но и об их разумности вообще. Говоря о современной документальной судебной сатире, тянет поразмышлять об истоках жанра – рисовании в английских судах, об американском комиксе как национальном способе преодоления Великой депрессии, о французской школе карикатуры, о том, что каждая революция рождает свой плакат, а каждая реакция – изобразительный язык условности. о том, как жанр комический и абсурдный становится способом спасительным вместить сознанием то, что непосильно эмоционально, невместимо как прямой документ… В сатирический сборник \"КафкаКодекс\" вошли комиксы на основе реальных судебных решений, которые были опубликованы на сайте \"Новой газеты\" осенью 2018 - весной 2019 годов. Они созданы как лучшими художниками-карикатуристами, давно работающими в СМИ, так и новыми для российского комикса авторами – от Андрея Бильжо до Жени Киямова. Итог каждой из этих историй подводят в своих комментариях под комиксами известные эксперты юридического и правозащитного сообществ, а по ссылкам на сайте \"Новой газеты\" можно найти и сами судебные решения и другие документы.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":4,"review":"","added":9999852,"hdCover":""},{"id":"09895eb","title":"Крутилы","author":"Фарел Далримпл","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003175397/140/9f74/Farel_Dalrimpl__Krutily.jpg","isbn":"978-5-91339-839-0","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Альтернативные комиксы","genres":["Комиксы","манга","графические романы"],"annotation":"Крутилы Фарелла Далримпла – бестселлер New York Times, поцелованный Майком Миньолой. Создатель \"Хеллбоя\" похвалил работу Далримпла, отметив красоту рисунка и интересных персонажей, сказав, что \"таким и должен быть комикс\". В центре сюжета – группа подростков, сражающаяся с монстрами, хлынувшими в наш мир из тёмной реальности. А впустили их самые главные герои – Шервуд и Орсон, сунувшись в пещеру, в которую было строжайше запрещено входить. И теперь только юные бойцы, называющие себя Крутилами, могут дать отпор наступающим Мрачникам.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":4,"review":"","added":9999851,"hdCover":""},{"id":"09895ea","title":"41 Ночь","author":"Егор Прутов,Роман Орлов","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004120254/140/2b2e/__41_Noch.jpg","isbn":"978-5-91339-908-3","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"У Альберта было всё, о чём можно только мечтать: спокойная жизнь, большой загородный дом, любимая жена и обожаемый маленький сын. Как говорят в народе: \"Не жизнь, а самая настоящая сказка\". Но у любой сказки есть тёмная сторона. Однажды ночью прямо из уютной детской кроватки пропадает ребёнок… Объятый паникой, отец тотчас бросается на поиски сына – Альберт уверен, что младенец был похищен ночным чудовищем с горящими жёлтыми глазами. Но словам мужчины не верит никто: ни следователи, ни психолог, ни даже родная жена. В поисках сына Альберт остаётся наедине с самим собой… И вскоре ему предстоит сделать страшное открытие.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":4,"review":"","added":9999850,"hdCover":""},{"id":"09895e9","title":"Metal Gear Solid. Тактический шпионский боевик. Омнибус","author":"Эшли Вуд","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003978840/140/300e/Eshli_Vud__Metal_Gear_Solid._Takticheskij_shpionskij_boevik._Omnibus.jpg","isbn":"978-5-04-107582-8","publisher":"Комильфо","pubDate":"2020","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"СНЕЙК ВЕРНУЛСЯ! В ваших руках полное собрание комикс-адаптации Metal Gear Solid и Metal Gear Solid: Sons of Liberty из-под кисти несравненного Эшли Вуда. На этих страницах вас ждёт настоящее возрождение знаменитой саги! Насладитесь мрачной, но захватывающей историей и узнайте, удастся ли Солиду Снейку в очередной раз спасти мир от нависшей террористической угрозы. Издание также включает пятистраничный нулевой выпуск Metal Gear Solid: Sons of Liberty, написанный Мэттом Фрэкшном.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":5,"review":"","added":9999849,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895e8","title":"Сабрина. Жуткие приключения","author":"Роберто Агирре-Сакаса","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002739624/140/a257/Roberto_AgirreSakasa__Sabrina._Zhutkie_priklyucheniya.jpg","isbn":"978-5-91339-579-5","publisher":"Комильфо","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы","Зарубежное фэнтези"],"annotation":"САБРИНА, МАЛЕНЬКАЯ ВЕДЬМА, - такой вы её ещё НИКОГДА не видели! ХОРРОР-ШЕДЕВР от двух мастеров своего дела - впервые в сборнике!  В канун своего шестнадцатилетняя юная ведьма Сабрина Спеллмен оказывается на распутье. Она должна выбрать между сверхъестественной судьбой и её смертным парнем, Харви. Но Мадам Сатана, заклятый враг её семьи из прошлого, прибыла в Гриндейл и обратила свой взгляд на юную ведьму. Сможет ли Сабрина дать отпор или же её ведьмовское будущее, равно как и школьная жизнь, резко оборвётся?  РОБЕРТО АГИРРЕ-САКАСА, писатель, получивший премию Харви (\"Арчи и ХОР\", \"Загробная Жизнь с Арчи\", \"Ривердейл\" от CW), и художник РОБЕРТ ХЭК (\"Доктор Кто\", \"Секретные Материалы\") подарили вам неповторимое и шокирующее переосмысление оккультного становления Сабрины, маленькой ведьмы.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-05","rating":4,"review":"","added":9999848,"hdCover":""},{"id":"09895e7","title":"Вечные","author":"Нил Гейман,Джон Ромита-мл.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007015896/140/9d5d/__Vechnye.jpg","isbn":"978-5-04-122575-9","publisher":"Комильфо","pubDate":"2022","language":"Русский","series":"Герои Marvel","genres":["Комиксы","манга","графические романы","Зарубежная фантастика"],"annotation":"Более тридцати пяти лет назад легенда комиксов Джек «Король» Кирби вернулся в Дом Идей с, быть может, самым громким сюжетом всех времён: он придумал Вечных! Комикс родился из интереса легендарного автора к вопросам происхождения человека и появления мифов. Как и многие другие работы Короля, «Вечные» опередили своё время.  Перенесёмся в 2006 год: звёздные авторы Нил Гейман и Джон Ромита-мл. бережно работают с идеями Кирби и создают собственную историю: искромётную, загадочную, невероятную. С этого момента персонажи мэтра неотъемлемая часть Вселенной Marvel. Во время Гражданской войны Marvel Вечные один за другим пробуждаются ото сна и узнают, что серьёзно ошибались, считая себя обычными людьми. Но учиться контролировать новые силы времени нет: герои оказываются в самом сердце смертельно опасной схватки, которая развернулась и во времени, и в пространстве.  В книге собраны комиксы «Вечные» #1-7.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-04","rating":4.5,"review":"","added":9999847,"hdCover":""},{"id":"09895e6","title":"Attack on Titan: Volume 24","author":"Hajime Isayama","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002706884/140/3a5e/Hajime_Isayama__Attack_on_Titan_Volume_24.jpg","isbn":"978-1632365354","publisher":"Kodansha Comics","pubDate":"2018","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"IT CATCHES UP TO YOU The world outside the Walls is vaster than Eren and his comrades could have ever imagined. Just beyond the shores of Paradis lies the country of Marley - home to Eren''s mortal enemy Reiner. He may have returned home, hoping to consign \"the Armor\" to his past, but some things can''t be so easily forgotten - and Reiner is about to be confronted by a certain someone he turned his back on...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-04","rating":5,"review":"","added":9999846,"hdCover":""},{"id":"09895e5","title":"Человек-бензопила. Книга 3. Несовершеннолетний. Бум-бум-бум","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007042521/140/1069/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_3._Nesovershennoletnij._Bumbumbum.jpg","isbn":"978-5-389-20739-4","publisher":"Азбука","pubDate":"2022","language":"Русский","series":"Графические романы","genres":["Комиксы","манга","графические романы"],"annotation":"Операция специального четвертого отдела в самом разгаре! Пока демоны и одержимые расправляются с ордами зомби, Аки Хаякава встречается лицом к лицу с Саватари, причастной к убийству его напарницы. Таинственная незнакомка сходу использует грязный прием: она натравливает на Хаякаву призрака, некогда помогавшего Химэно. Вот только Саватари не в курсе, что Аки заключил договор с еще одним демоном и теперь обладает новыми силами… Тем временем Дэндзи вновь сталкивается с якудза, мечтающим отомстить за смерть своего дедушки. Прошлое сражение обернулось поражением для молодого охотника. Чем же закончится очередная битва?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-04","rating":4.5,"review":"","added":9999845,"hdCover":""},{"id":"09895e4","title":"Человек-бензопила. Книга 2. Убить Дэндзи. Мощь огнестрельного оружия","author":"Тацуки Фудзимото","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006932250/140/b140/Tatsuki_Fudzimoto__Chelovekbenzopila._Kniga_2._Ubit_Dendzi._Mosch_ognestrelnogo_.jpg","isbn":"978-5-389-20392-1","publisher":"Азбука","pubDate":"2021","language":"Русский","series":"домашняя библиотека","genres":["Комиксы","манга","графические романы"],"annotation":"Дэндзи и его коллеги выезжают на вызов в отель «Морин», где оказываются заперты в бесконечной временной петле на восьмом этаже: хитроумная ловушка, которую подстроил демон, не позволяет охотникам выбраться наружу. Ситуация не сулит ничего хорошего… Однако чудовище предлагает сделку: если ему скормят Дэндзи, оно освободит весь отряд. Какое же решение примут коллеги охотника-новобранца? Обменяют ли они жизнь одного человека на жизнь всей команды? И как в таких обстоятельствах себя поведет сам Дэндзи?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-04","rating":4.5,"review":"","added":9999844,"hdCover":""},{"id":"09895e3","title":"Семь Смертных Грехов. Книга 7","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006853809/140/d9e6/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_7.jpg","isbn":"978-5-91-996338-7","publisher":"XL Media","pubDate":"2021","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"Святые рыцари, осознавшие, что все это время ошибались насчет Смертных Грехов, один за другим встают на их сторону. Но магистр Хендриксен, превратившийся в демона, оказывается слишком силен. Смертные Грехи один за другим терпят поражение, и даже Мелиодасу, похоже, нечего противопоставить ужасающей мощи Хендриксена. В самый безнадежный момент, когда тот уже готовится убить Мелиодаса, помощь приходит оттуда, откуда никто ее не ждал...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999843,"hdCover":""},{"id":"09895e2","title":"Attack on Titan: Volume 23","author":"Hajime Isayama","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002473223/140/221a/Hajime_Isayama__Attack_on_Titan_Volume_23.jpg","isbn":"978-1632364630","publisher":"Kodansha Comics","pubDate":"2017","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999842,"hdCover":""},{"id":"09895e1","title":"Attack on Titan: Volume 22","author":"Hajime Isayama","type":"Книга","cover":"https://s1.livelib.ru/boocover/1002135109/140/9c4e/Hajime_Isayama__Attack_on_Titan_Volume_22.jpg","isbn":"978-1632364258","publisher":"Kodansha Comics","pubDate":"2017","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Зарубежное фэнтези"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999841,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
