  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895df","title":"Семь Смертных Грехов. Книга 6","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005516676/140/078b/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_6.jpg","isbn":"978-5-91996-333-2","publisher":"XL Media","pubDate":"2021","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"В столице Лионесса продолжаются ожесточенные схватки между Смертными Грехами и самыми высокопоставленными из Святых рыцарей. Кинг одолел своего давнего друга-врага Хельбрама, Мелиодас бьется с Гилсандером, король Артур — с магистром Хендриксеном. У всех свои причины сражаться, и никто не собирается уступать. Сильнейшей волшебнице королевства тоже предстоит столкнуться с нежданным и могучим противником — в котором Смертные Грехи узнают давно потерянного союзника!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4.5,"review":"","added":9999839,"hdCover":""},{"id":"09895de","title":"Семь Смертных Грехов. Книга 5","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004783782/140/e3fa/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_5.jpg","isbn":"978-5-91996-335-6","publisher":"XL Media","pubDate":"2020","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"Мелиодас, Бан и Гаутер отправляются в столицу, чтобы спасти похищенную Элизабет. Казалось бы, втроем у них нет шансов против войска Святых рыцарей, но тут в битву вступает третья сила: Артур, король Камелота, во главе целой армии. Да и между Святыми рыцарями, как оказалось, давно зрели разногласия… Бывшие союзники становятся врагами, весь город превращается в арену кровопролитной битвы — неужели это начало Священной войны?..","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4.5,"review":"","added":9999838,"hdCover":""},{"id":"09895dd","title":"Семь Смертных Грехов. Книга 4","author":"Накаба Судзуки","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1004691946/140/96a7/Nakaba_Sudzuki__Sem_Smertnyh_Grehov._Kniga_4.jpg","isbn":"978-5-91996-327-1","publisher":"XL Media, ЭксЭл Медиа","pubDate":"2020","language":"Русский","series":"Семь Смертных Грехов / Nanatsu no Taizai","genres":["Комиксы","манга","графические романы"],"annotation":"В миг самого черного отчаяния, когда союзники проиграли битву, принцесса Элизабет обращается к тому, кто некогда дал ей надежду и всегда спасал от любых невзгод — к Мелиодасу, забыв о том, что сейчас он бессилен ей помочь, запертый внутри янтаря богинь, подвески принцессы Вероники. И случается невероятное: отчаянный крик Элизабет освобождает Мелиодаса. Он вступает в смертельную схватку со Святым рыцарем Хельбрамом, до того играючи расправившимся с Кингом. Но покинувший магическую темницу Мелиодас совсем на себя не похож: это нечто страшное, потустороннее. Что с ним произошло? Неужели это тот самый добряк, что всегда избегал убийств любой ценой? И если это его истинное лицо, то кто же он на самом деле такой? Сколько еще мрачных тайн таит прошлое Смертных Грехов?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4.5,"review":"","added":9999837,"hdCover":""},{"id":"09895dc","title":"Щ.И.Т. Секретная история","author":"Дэвид Уокер,Джоди Хаузер,Иммонен Кэтрин","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002743418/140/8d72/__Sch.I.T._Sekretnaya_istoriya.jpg","isbn":"978-5-04-091860-7","publisher":"Fanzon","pubDate":"2018","language":"Русский","series":"Комиксы (покет)","genres":["Комиксы","манга","графические романы"],"annotation":"Юбилейный сборник, посвященный 50-летию \"Щ.И.Т.\", раскрывает тайны самых загадочных сотрудников агентства. Отправьтесь в прошлое и узнайте, как Пегги Картер принимали в \"Щ.И.Т.\"! Встреча Дейзи \"Скай\" Джонсон с Нелюдем заставит вас вздрогнуть! А на задании в прошлом веке Нику Фьюри придется работать бок о бок с отцом, и им обоим придётся смотреть в оба! А также: первое появление Ника Фьюри-старшего и его борьба с нацистами во время Второй мировой в составе \"Воющих коммандос\"!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4,"review":"","added":9999836,"hdCover":""},{"id":"09895db","title":"Attack on Titan: Volume 20","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001830006/140/6bfe/Hajime_Isayama__Attack_on_Titan_Volume_20.jpg","isbn":"978-1-63236-309-1","publisher":"Kodansha Comics","pubDate":"2016","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The Survey Corps''s quest for the truth of the world inside the Walls has brought them back to Titan-infested Shiganshina District, a mere stone''s throw from Eren''s childhood home. They have come to execute Erwin''s final gambit, reclaiming Wall Maria and the secrets of humanity''s past. But the Colossus Titan, the Armored Titan, and the Beast Titan have been waiting for them, and saving humanity will require the most difficult sacrifice the Corps has ever had to make...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999835,"hdCover":""},{"id":"09895da","title":"Attack on Titan. Vol. 19","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001619257/140/c28b/Hajime_Isayama__Attack_on_Titan._Vol._19.jpg","isbn":"978-1-63236-259-9","publisher":"Kodansha Comics","pubDate":"2016","language":"Английский","series":"Attack on Titan","genres":["Боевое фэнтези","Манга"],"annotation":"The Survey Corps is engaged in a desperate, final battle to retake Wall Maria and defeat the Titans once and for all. Eren must use his new powers to seal the holes created five years ago in the Shiganshina District gates, not to mention to finally reach the basement of his old home and find what secrets lie hidden there. But the most difficult part of the operation will be surviving whatever clever traps the Colossus Titan, Armored Titan, and Beast Titan have prepared for them! Now that Erwin is gambling with every last human life, who will triumph?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999834,"hdCover":""},{"id":"09895d9","title":"Attack on Titan: Volume 18","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001477153/140/f3ab/Hajime_Isayama__Attack_on_Titan_Volume_18.jpg","isbn":"978-1-63236-211-7","publisher":"Kodansha Comics","pubDate":"2016","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"The Survey Corps has overthrown the Royal Government and swept away the tyranny of the king. The next step: Move to retake Wall Maria, with the helpf of a newly-discovered metallic ore and Eren''s miraculous Titan hardening powers. But as humanity pulls together, its enemies also unite beyond the Walls... now that the Beast Titan has joined Reiner and Bertolt, what havoc will they wreak?","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999833,"hdCover":""},{"id":"09895d8","title":"«Вечные» Джека Кирби. Полное издание","author":"Джек Кирби","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007094226/140/a32b/Dzhek_Kirbi__Vechnye_Dzheka_Kirbi._Polnoe_izdanie.jpg","isbn":"978-5-04-121240-7","publisher":"Комильфо","pubDate":"2022","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Король комиксов Джек Кирби представляет новейший пантеон богов Marvel!  Представьте себе племя бессмертных созданий, обладающих почти неисчерпаемым арсеналом сверхчеловеческих способностей! Однажды сразившись с греческими, римскими и скандинавскими богами за власть над людьми, эти создания сами стали объектами поклонения, а после отправились изучать звёзды. Они — вечные, ещё один фрагмент космической мифологии. Их противники девианты тоже тайно живут на Земле, а громадные космические существа, создавшие вечных и девиантов, Целестиалы, вот-вот прибудут на планету и решат её участь. Это только начало грандиозной космогонии, саге о богах и людях, придуманной Джеком «Королём» Кирби, одним из создателей Капитана Америка, Людей Икс, Мстителей и многих других!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4.5,"review":"","added":9999832,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895d7","title":"Attack on Titan: Volume 17","author":"Hajime Isayama","type":"Манга","cover":"https://s1.livelib.ru/boocover/1001472865/140/3fe6/Hajime_Isayama__Attack_on_Titan_Volume_17.jpg","isbn":"978-1-63236-112-7","publisher":"Kodansha Comics","pubDate":"2015","language":"Английский","series":"Attack on Titan","genres":["Манга"],"annotation":"Thanks to Rod Reiss, Eren finally knows the terrible truth behind how he acquired his Titan powers, and the depth of his father''s crimes. The king orders his daughter Historia to kill Eren and restore the power of the Titans to its rightful place, but she chooses her own selfish path: survival. As the cavern crumbles around the Survey Corps, Eren must make another last-minute decision, with the lives of all his friends in the balance.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":5,"review":"","added":9999831,"hdCover":""},{"id":"09895d6","title":"Джек Кирби. Лучшее","author":"Джек Кирби","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005449476/140/7653/Dzhek_Kirbi__Dzhek_Kirbi._Luchshee.jpg","isbn":"978-5-04-111713-9","publisher":"Комильфо","pubDate":"2020","language":"","series":"Классика Marvel. Лучшее","genres":["Комиксы","манга","графические романы"],"annotation":"Вклад Джека \"Короля\" Кирби в развитие комиксов невозможно переоценить... и ещё сложнее представить современные комиксы без его наработок. Он был одним из новаторов, превративших газетные стрипы в совершенно новый вид американского искусства. За сорок лет работы Кирби с его воображением трудолюбием и неиссякаемым сыграл важнейшую роль в создании десятков незабываемых, культовых героев Marvel Comics. в их числе Капитан Америка, Фантастическая Четвёрка, Люди Икс и Халк. Джек Кирби, один из величайших создателей комиксов в истории, по праву носит титул Короля.  Внутри книги вы найдёте практически все жанры, с которыми довелось поработать знаменитому художнику: научная фантастика, супергероика, вестерн, мистика, военные комиксы и бурные фантазии на тему альтернативных вселенных. И в каждом из них вы почувствуете руку непревзойдённого мастера, ведь Король всегда всё делал на \"отлично\". Также вас ждут важные вехи в истории супергероев, которые уже давно заняли место среди икон поп-культуры: первое появление Капитана Америка, вторжение Галактуса и Серебряного сёрфера на Землю, история происхождения Халка и многое другое!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4.5,"review":"","added":9999830,"hdCover":""},{"id":"09895d5","title":"Что если?.. Звёзды Marvel стали Фантастической Четвёркой","author":"Стэн Ли","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1005992215/140/6026/Sten_Li__Chto_esli.._Zvjozdy_Marvel_stali_Fantasticheskoj_Chetvjorkoj.jpg","isbn":"978-5-04-118120-8","publisher":"Комильфо","pubDate":"2021","language":"","series":"Marvel. Альтернатива","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-03","rating":4,"review":"","added":9999829,"hdCover":""},{"id":"09895d4","title":"Хэнк Джонсон, агент Гидры","author":"Майкл Уолш,Мэтт Уилсон,Дэвид Мэндел","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002804381/140/cebb/__Henk_Dzhonson_agent_Gidry.jpg","isbn":"978-5-91339-659-4","publisher":"Комильфо","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999828,"hdCover":""},{"id":"09895d3","title":"Что за... Свин Паук?!","author":"Стэн Ли,Барри Даттер,Джин-Марк Туссант,Дуг Райс,Рурик Тайлер.,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003326388/140/61b4/__Chto_za..._Svin_Pauk.jpg","isbn":"978-5-04-106854-7","publisher":"Комильфо","pubDate":"2019","language":"Русский","series":"Что за?!","genres":["Комиксы","манга","графические романы"],"annotation":"Встречайте следующий выпуск ваших любимых пародийных комиксов Mаrvel! Теперь авторы хорошенько пошутят над Свином-Пауком и Доктором Думом, Серебряным Сёрфером и Галактусом, Халком и деревенщинами, отправят Фантастическую Четвёрку сниматься в кино, а ещё убьют самого любимого героя Marvel! Не пропустите!","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3,"review":"","added":9999827,"hdCover":""},{"id":"09895d2","title":"Черепашки-Ниндзя №9","author":"Кевин Истмен и Питер Лерд","type":"Книга","cover":"https://s1.livelib.ru/boocover/1007087536/140/dd75/Kevin_Istmen_i_Piter_Lerd__CherepashkiNindzya_No9.jpg","isbn":"9772313408156","publisher":"Illusion Studios","pubDate":"2015","language":"","series":"TMNT Volume 1","genres":[],"annotation":"","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999826,"hdCover":""},{"id":"09895d1","title":"Что за... Перчатка бесконечности?!","author":"Барта Х.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003013677/140/86e9/Barta_H.__Chto_za..._Perchatka_beskonechnosti.jpg","isbn":"978-5-04-102869-5","publisher":"Комильфо","pubDate":"2019","language":"","series":"Что за?!","genres":["Комиксы","манга","графические романы"],"annotation":"Самые знаменитые пародийные комиксы Marvel наконец-то выходят на русском языке! Внутри каждого выпуска вы сможете несколько историй о могучих героях и коварных злодеях, таких как Свин-Паук, Капеллан Америка, Капитан Шизам и, конечно же, зловещий Термос, готовый одним щелчком своей варежки бесконечности уничтожить половину Вселенной. Правда, совсем не так, как вы думаете. Окунитесь в невероятную атмосферу безумного веселья вместе с знаковыми сценаристами и художниками Marvel!  В «Перчатке бесконечности» вас ждет встреча со зловещим Термосом готовым одним щелчком своей варежки бесконечности уничтожить половину Вселенной. Правда, совсем не так, как вы думаете… Также в этом комиксе упоминается один из самых смешных героев вселенной, Свин-Паук, являющийся пародией на Человека-Паука. Эта антропоморфная суперзверушка уже крепко полюбилась фанатам и нашла отражение во множестве комиксов Марвел.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3,"review":"","added":9999825,"hdCover":""},{"id":"09895d0","title":"Собакистаун (Собакистан: Спецвыпуск)","author":"Виталий Терлецкий,Катя","type":"Книга","cover":"https://s1.livelib.ru/boocover/1006973785/140/ca94/__Sobakistaun_Sobakistan_Spetsvypusk.jpg","isbn":"978-5-6046878-2-6","publisher":"Терлецки Комикс","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Собакистаун не пахнет бензином, не шумит автомобилями, в нем нет выхлопных газов. Его можно обойти за десять минут. Его жители — чистопородные собаки. Здесь царят дружба, взаимовыручка, уважение и взаимопомощь. Он маленький, уютный и чистый. Всё идеально, да? Или так только кажется? На этот раз спецвыпуск во вселенной «Собакистана » погрузит вас в неповторимую эстетику одноэтажной Америки пятидесятых годов.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999824,"hdCover":""}]');

INSERT OR IGNORE INTO library_items (
  id,title,author,item_type,reading_status,cover_url,hd_cover_url,isbn,publisher,
  publication_date,language,series,genres,annotation,read_date,rating,review,quotes,
  acquired_on,purchase_cost_cents,is_sold,sold_on,sale_price_cents,added
)
SELECT
  json_extract(value,'$.id'),json_extract(value,'$.title'),json_extract(value,'$.author'),
  json_extract(value,'$.type'),json_extract(value,'$.status'),json_extract(value,'$.cover'),
  json_extract(value,'$.hdCover'),json_extract(value,'$.isbn'),json_extract(value,'$.publisher'),
  json_extract(value,'$.pubDate'),json_extract(value,'$.language'),json_extract(value,'$.series'),
  json_extract(value,'$.genres'),json_extract(value,'$.annotation'),json_extract(value,'$.read'),
  json_extract(value,'$.rating'),json_extract(value,'$.review'),json_extract(value,'$.quotes'),
  json_extract(value,'$.acquired'),CASE WHEN json_extract(value,'$.cost') IS NULL THEN NULL ELSE round(json_extract(value,'$.cost')*100) END,
  CASE WHEN json_extract(value,'$.sold') THEN 1 ELSE 0 END,json_extract(value,'$.soldDate'),
  CASE WHEN json_extract(value,'$.soldPrice') IS NULL THEN NULL ELSE round(json_extract(value,'$.soldPrice')*100) END,
  json_extract(value,'$.added')
FROM json_each('[{"id":"09895cf","title":"Дни Демона. Люди Икс","author":"Пич Момоко","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006961107/140/dcec/Pich_Momoko__Dni_Demona._Lyudi_Iks.jpg","isbn":"978-5-6047218-0-3","publisher":"Alpaca","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Добро пожаловать в мир, полный демонов, духов, монстров и магии. Такой вселенную Marvel вы ещё не видели. Это...  «Дни Демона» Пич Момоко  Ещё совсем недавно Пич была одной из многих художниц с аллеи авторов, что робко пробиваются в индустрию, печатая за свой счёт открытки и собственные комиксы. Но внезапно она становится той самой одной на миллион, и MARVEL подписывают с ней эксклюзивный контракт. И даже более того - выдают ей собственную вселенную, где она вольна перекраивать по своему вкусу приевшиеся образы и легенды дома идей.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999823,"hdCover":""},{"id":"09895ce","title":"Лунный рыцарь (2021) #1","author":"Джед Маккэй,Маккэй Дж.","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006972348/140/867b/__Lunnyj_rytsar_2021_1.jpg","isbn":"978-5-6047218-1-0","publisher":"Alpaca","pubDate":"2021","language":"","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Наёмник Марк Спектор умер и переродился в тени Хонсу — египетского бога луны. Спектор стал Лунным Рыцарем — кулаком Хонсу в борьбе со злом. Основав «Полночную миссию», он защищает всех ночных путников","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999822,"hdCover":""},{"id":"09895cd","title":"Собеседование","author":"Сергей Титов,Сергей Назаров,Дмитрий Елецкий,Ярослав Абрамов,Алексей Иванов,показать всех","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1007077855/140/87f5/__Sobesedovanie.jpg","isbn":"978-5-6046988-3-9","publisher":"Alpaca","pubDate":"2021","language":"Русский","series":"Из стекла и бетона","genres":["Комиксы","манга","графические романы"],"annotation":"«Собеседование» — первая история из постнуарного альманаха «Из стекла и бетона».  Безымянный герой спешит на главное собеседование в своей жизни, но поезд внезапно останавливается посреди поля. И все бы ничего, но молодой человек никак не может понять, почему пассажиры с ужасом вглядываются в этот дивный пейзаж с открытки...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999821,"hdCover":""},{"id":"09895cc","title":"Чудесные моменты. Нэмор Подводник","author":"Алан Бреннерт","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1006805386/140/0b23/Alan_Brennert__Chudesnye_momenty._Nemor_Podvodnik.jpg","isbn":"978-5-04-123257-3","publisher":"Комильфо","pubDate":"2021","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Война не проходит бесследно — даже для супергероев. Для тех, кому повезло вернуться с фронта живыми, борьба никогда не заканчивается — ведь теперь их одолевают воспоминания об увиденных ужасах. Бетти Дин, девушка Нэмора Подводника, решила сводить возлюбленного на свидание в парк развлечений... но эхо войны настигло их и там.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4,"review":"","added":9999820,"hdCover":""},{"id":"09895cb","title":"Замок из песка","author":"Фредерик Питерс,Пьер Оскар Леви","type":"Книга","cover":"https://s1.livelib.ru/boocover/1005621454/140/57f0/__Zamok_iz_peska.jpg","isbn":"978-5-907305-20-5","publisher":"Бумкнига","pubDate":"2021","language":"Русский","series":"","genres":[],"annotation":"Молодая пара, несколько туристов и беженец в одно и то же время оказываются в уединенной бухте, окруженной густо заросшими скалами. Но идиллическую картину рушат два загадочных события: кристально чистые воды озера выносят на берег труп женщины, а все собравшиеся на пляже начинают преждевременно стареть. В своей тревожной фантастической книге Питерс и Леви говорят с читателем о страхе старения, неизбежности смерти, взрослении и новой этике.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999819,"hdCover":""},{"id":"09895ca","title":"Марсианские хроники. Авторизованная графическая адаптация","author":"Рэй Брэдбери,Деннис Калеро","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1003837328/140/a26e/__Marsianskie_hroniki._Avtorizovannaya_graficheskaya_adaptatsiya.jpg","isbn":"978-5-04-110757-4","publisher":"Fanzon","pubDate":"2020","language":"Русский","series":"Комиксы. Современная классика","genres":["Комиксы","манга","графические романы"],"annotation":"Сначала они прибывали горстками. Затем сотнями. Миллионами. Они смахнули с поверхности Марса величавую, гибнущую цивилизацию, чтобы выстроить города и торговые центры. Марс стал воплощением безудержных грез. Превратился в новую Землю взамен старой — утопающей в войнах и мусоре. Стал чистым холстом для безумных причуд и самых мрачных наваждений человечества. И земляне, что прибыли покорять Красную планету, обнаружили, что Марс покорил их самих.  В авторизованной графической адаптации «Марсианских хроник» классик мировой литературы Рэй Брэдбери приглашает нас отправиться на Марс, чтобы остаться там навсегда.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999818,"hdCover":""},{"id":"09895c9","title":"Магнето. Том 2. Смена ролей","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002867903/140/e9ba/Kallen_Bann__Magneto._Tom_2._Smena_rolej.jpg","isbn":"978-5-6040824-2-3","publisher":"Jellyfish Jam","pubDate":"2018","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Глава Братства Злых Мутантов. Преступник на пути исправления. Покровитель Геноши. Изгой. Магнето не привыкать к смене ролей. Вот и сейчас он не только помогает Скотту Саммерсу и его команде, но и в одиночку мстит всем, кто нападает на мутантов. Он идет по следу преступного синдиката, разрабатывающего ГРМ - искусственный гормон, дарующий или усиливающий суперспособности. Но, помимо мести, у Магнето есть и другие цели...","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":3.5,"review":"","added":9999817,"hdCover":""},{"id":"09895c8","title":"Магнето. Том 1. Дурная слава","author":"Каллен Банн","type":"Комикс","cover":"https://s1.livelib.ru/boocover/1002688748/140/b65f/Kallen_Bann__Magneto._Tom_1._Durnaya_slava.jpg","isbn":"978-5-9909879-1-3","publisher":"Jellyfish Jam","pubDate":"2017","language":"Русский","series":"","genres":["Комиксы","манга","графические романы"],"annotation":"Он был главным противником Людей Икс. Он был грозой человечества. Он был надеждой и защитником мутантов. Он был повелителем магнетизма. У него отобрали всё, но он никогда не сдавался. Он - Магнето. И теперь он - одинокий мститель, который без жалости расправится с каждым, кто угрожает его народу, будь то новые Стражи, правительство или безжалостные Мародеры, ответственные за ужасную резню мутантов.  Сольная серия Магнето разительно отличается от привычных рассказов о Людях Икс - гораздо больше общего у нее с комиксами о Карателе и других брутальных антигероях. И уж точно она гораздо жестче - Люди Икс никогда не убивают своих противников, а Магнето... в общем, не зря он работает один.","acquired":"","cost":null,"sold":false,"soldDate":"","soldPrice":null,"quotes":[],"status":"Прочитал","read":"2022-02","rating":4.5,"review":"","added":9999816,"hdCover":""}]');
